import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.esapi.ESAPI;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeOutput = ESAPI.encoder().encodeForHTML(userInput); // Properly encode user input

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>Secure Servlet</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome, " + safeOutput + "</h1>"); // Outputting properly encoded user input into the HTML response
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
